import {Component, Injector} from '@angular/core';
import {environment} from "src/environments/environment";
import {FormBuilder, FormGroup} from "@angular/forms";
import {
  AlignEnum,
  ApiService, AuthoritiesService,
  BaseSearchComponent,
  ColumnModel, ColumnTypeEnum,
  FormStateService,
  SelectModel, TablePagingRequestModel,
  UtilsService,
} from '@c10t/nice-component-library';
import { TranslateService } from '@ngx-translate/core';
import {ChartConfiguration} from "chart.js";
import {ActivatedRoute, Router} from "@angular/router";
import {
  createLabelChart,
  DASHBOARD_PAYBACK_COLUMNS
} from "src/app/modules/project-information/dashboard/dashboard.config";
import Chart from "chart.js/auto";
import {ChartOptionsUtils} from "src/app/shared/utils/ChartOptionsUtils";



@Component({
  selector: 'app-dashboard-payback-over-time',
  standalone: false,
  templateUrl: './dashboard-payback-over-time.component.html',
  styles: [``],
})
export class DashboardPaybackOverTimeComponent extends BaseSearchComponent{
  optionsData: SelectModel[] = [
    {
      displayValue: 'Option 1', rawData: 1, disabled: false,
      value: 1
    },
    {
      displayValue: 'Option 1', rawData: 2, disabled: false,
      value: 2
    }
  ];
  filterForm!: FormGroup;
  moduleName: string = ''
  columns: ColumnModel[] = [...DASHBOARD_PAYBACK_COLUMNS];
  overViewCharBarLine!: Chart
  showLabel = createLabelChart()

  constructor(protected fb: FormBuilder,
              protected router: Router,
              protected apiService: ApiService,
              protected utilsService: UtilsService,
              protected formStateService: FormStateService,
              protected translateService: TranslateService,
              protected injector: Injector,
              protected activatedRoute: ActivatedRoute,
              protected authoritiesService: AuthoritiesService,
          ) {
    super(
      router, apiService, utilsService, formStateService, translateService, injector, activatedRoute, authoritiesService,
      fb.group({}),)
  }

  ngOnInit() {
    this.initFilterForm()
  }
  ngAfterViewInit() {
    this.initOverviewChart()
  }

  initOverviewChart() {
    if (this.overViewCharBarLine) {
      this.overViewCharBarLine.destroy()
    }
    const canvasPaybackOverTime = document.getElementById('canvas-payback-over-time') as HTMLCanvasElement;
    if (canvasPaybackOverTime) {
      const ctx: any = canvasPaybackOverTime.getContext('2d');
      this.overViewCharBarLine = new Chart(ctx, {
        type: 'line',
        data: {
          labels: ['T1', 'T2', 'T3', 'T4', 'T5', 'T6', 'T7', 'T8', 'T9', 'T10', 'T11', 'T12'],
          datasets: [
            {
              type: 'bar',
              label: 'Dòng tiền lũy kế TH',
              data: [15, 48, 58, 52, 40, 100, 55, 80, 15, 95, 105, 68],
              backgroundColor: 'rgba(255, 35, 82, 1)',
              borderColor: 'rgba(255, 35, 82, 1)',
              borderWidth: 1,
              yAxisID: 'y',
              order: 2
            },
            {
              type: 'bar',
              label: 'Dòng tiền lũy kế TH',
              data: [18, 45, 55, 12, 42, 95, 60, 85, 20, 100, 110, 70],
              backgroundColor: 'rgba(22, 179, 100, 1)',
              borderColor: 'rgba(22, 179, 100, 1)',
              borderWidth: 1,
              yAxisID: 'y',
              order: 2
            },
            {
              type: 'line',
              label: 'Dòng tiền lũy kế KH',
              data: [65, 70, 68, 75, 72, 78, 80, 77, 82, 85, 83, 90],
              borderColor: 'rgba(22, 179, 100, 1)',
              backgroundColor: 'rgba(22, 179, 100, 1)',
              borderWidth: 3,
              fill: false,
              tension: 0.4,
              yAxisID: 'y1',
              pointRadius: 5,
              pointHoverRadius: 7,
              pointBackgroundColor: 'rgba(22, 179, 100, 1)',
              pointBorderColor: 'rgba(22, 179, 100, 1)',
              pointBorderWidth: 2,
              order: 1
            },
            {
              type: 'line',
              label: 'Đầu tư lũy kế KH',
              data: [60, 68, 65, 70, 75, 72, 85, 80, 78, 88, 85, 95],
              borderColor: 'rgba(255, 35, 82, 1)',
              backgroundColor: 'rgba(255, 35, 82, 1)',
              borderWidth: 3,
              fill: false,
              tension: 0.4,
              yAxisID: 'y1',
              pointRadius: 5,
              pointHoverRadius: 7,
              pointBackgroundColor: 'rgba(255, 35, 82, 1)',
              pointBorderColor: 'rgba(255, 35, 82, 1)',
              pointBorderWidth: 2,
              order: 1
            },
          ],
        },
        options: ChartOptionsUtils.chartBarLineOptions,
        plugins: [this.showLabel]
      })
    }
  }

  initFilterForm() {
    this.filterForm = this.fb.group({
      projectTeam: [null],
      frequency: [null],
      project: [null],
      Company: [null],
      startDate: [null],
      endDate: [null]
    });
  }

  onFilterApply() {
    if (this.filterForm.valid) {
      const formValue = this.filterForm.value;
    }
  }

  onResetFilter() {
    this.filterForm.reset()
  }

  environment = environment;
}
