import { NgModule } from '@angular/core';
import { SharedModule } from 'src/app/shared';
import { TranslateLoader, TranslateModule } from '@ngx-translate/core';
import { HttpClient } from '@angular/common/http';
import { TranslateLoaderFactoryHelper } from 'src/app/core';
import { ModuleNameEnum } from 'src/app/shared/enums/module.name.enum';
import { DashboardChildRoutingModule } from './dashboard-child.routing.module';
import {
  DashboardPaybackOverTimeComponent
} from './dashboard-payback-over-time/dashboard-payback-over-time.component';
import {
  DashboardPaybackSnapshotComponent
} from './dashboard-payback-snapshot/dashboard-payback-snapshot.component';
import {
  DashboardProductivityPersonComponent
} from './dashboard-productivity-person/dashboard-productivity-person.component';
import {
  DashboardProductionOutputComponent
} from './dashboard-production-output/dashboard-production-output.component';
import {
  DashboardRevenueInventoryComponent
} from './dashboard-revenue-inventory/dashboard-revenue-inventory.component';
import {
  DashboardCostPlanComponent
} from './dashboard-cost-plan/dashboard-cost-plan.component';
import {
  DashboardCashFlowPlan
} from './dashboard-dashboard-cash-flow-plan/dashboard-cash-flow-plan';

export function translateLoaderFactory(http: HttpClient): any {
  return new (TranslateLoaderFactoryHelper.forModule(ModuleNameEnum.PROJECT))(http);
}

@NgModule({
  declarations: [
    DashboardPaybackOverTimeComponent,
    DashboardPaybackSnapshotComponent,
    DashboardProductivityPersonComponent,
    DashboardProductionOutputComponent,
    DashboardRevenueInventoryComponent,
    DashboardCostPlanComponent,
    DashboardCashFlowPlan,
  ],
  imports: [
    SharedModule,
    TranslateModule.forChild({
      loader: {
        provide: TranslateLoader,
        useFactory: translateLoaderFactory,
        deps: [HttpClient],
      },
      isolate: true,
    }),
    DashboardChildRoutingModule
  ]
})
export class DashboardChildModule {}

