import {Component, OnInit} from '@angular/core';
import {AlignEnum, ColumnModel, SelectModel} from "@c10t/nice-component-library";
import {FormBuilder, FormGroup} from "@angular/forms";
import {ChartConfiguration, ChartOptions} from "chart.js";
import {environment} from "src/environments/environment";
import {DASHBOARD_PAYBACK_COLUMNS} from "src/app/modules/project-information/dashboard/dashboard.config";
import {ChartOptionsUtils} from "src/app/shared/utils/ChartOptionsUtils";
import Chart from "chart.js/auto";

@Component({
  selector: 'app-dashboard-payback-snapshot',
  standalone: false,
  templateUrl: './dashboard-payback-snapshot.component.html',
  styles: ''
})
export class DashboardPaybackSnapshotComponent implements OnInit {
  optionsData: SelectModel[] = [
    {
      displayValue: 'Option 1', rawData: 1, disabled: false,
      value: 1
    },
    {
      displayValue: 'Option 1', rawData: 2, disabled: false,
      value: 2
    }
  ];
  filterForm!: FormGroup;
  moduleName: string = ''
  columns: ColumnModel[] = [...DASHBOARD_PAYBACK_COLUMNS];
  overViewCharBarLine!: Chart
  protected readonly environment = environment;

  constructor(protected fb: FormBuilder) {
  }

  ngOnInit() {
    this.initFilterForm()
  }

  ngAfterViewInit() {
    if (this.overViewCharBarLine) {
      this.overViewCharBarLine.destroy()
    }
    const canvasPaybackProjectOverTime = document.getElementById('canvas-payback-project-over-item');
    if (canvasPaybackProjectOverTime) {
      const ctx = (canvasPaybackProjectOverTime as HTMLCanvasElement).getContext('2d');
      if (!ctx) return;
      this.overViewCharBarLine = new Chart(ctx, {
        type: 'bar',
        data: {
          labels: ['Dự án 1', 'Dự án 2', 'Dự án 3', 'Dự án 4', 'Dự án 5', 'Dự án 6'],
          datasets: [
            {
              type: 'bar',
              label: 'Hoàn vốn dự án TH',
              data: [15, 48, 58, 52, -30, 100],
              backgroundColor: 'rgb(4,198,36)',
              borderColor: 'rgb(4,198,36)',
              borderWidth: 1,
              yAxisID: 'y',
              order: 2
            },
            {
              type: 'line',
              label: 'Dòng tiền lũy kế KH',
              data: [65, 70, 68, 75, 72, 78,],
              borderColor: 'rgb(200,8,30)',
              backgroundColor: 'rgb(200,8,30)',
              borderWidth: 3,
              fill: false,
              yAxisID: 'y1',
              pointRadius: 5,
              pointHoverRadius: 7,
              pointBackgroundColor: 'rgb(200,8,30)',
              pointBorderColor: 'rgb(200,8,30)',
              pointBorderWidth: 2,
              order: 1
            },
          ],
        },
        options: ChartOptionsUtils.chartBarLineOptions,
      })
    }
  }

  initFilterForm() {
    this.filterForm = this.fb.group({
      projectTeam: [null],
      frequency: [null],
      project: [null],
      Company: [null],
      startDate: [null],
      endDate: [null]
    });
  }

  onFilterApply() {
    if (this.filterForm.valid) {
      const formValue = this.filterForm.value;
    }
  }

  onResetFilter() {
    this.filterForm.reset()
  }

}
