import { Component } from '@angular/core';
import {ColumnModel, SelectModel} from "@c10t/nice-component-library";
import {FormBuilder, FormGroup} from "@angular/forms";
import {DASHBOARD_PAYBACK_COLUMNS} from "src/app/modules/project-information/dashboard/dashboard.config";
import {ChartConfiguration} from "chart.js";
import {environment} from "src/environments/environment";
import Chart from "chart.js/auto";
import {ChartOptionsUtils} from "src/app/shared/utils/ChartOptionsUtils";

@Component({
  selector: 'app-dashboard-productivity-person',
  standalone: false,
  templateUrl: './dashboard-cost-plan.component.html',
  styles: ''
})
export class DashboardCostPlanComponent {
  optionsData: SelectModel[] = [
    {
      displayValue: 'Option 1', rawData: 1, disabled: false,
      value: 1
    },
    {
      displayValue: 'Option 1', rawData: 2, disabled: false,
      value: 2
    }
  ];
  filterForm!: FormGroup;
  moduleName: string = ''
  columns: ColumnModel[] = [...DASHBOARD_PAYBACK_COLUMNS];
  protected readonly environment = environment;
  overViewCharLine!: Chart
  constructor(protected fb: FormBuilder) {
  }
  ngOnInit() {
    this.initFilterForm()
  }
  ngAfterViewInit() {
    this.initOverviewChart()
  }

  initOverviewChart() {
    if (this.overViewCharLine) {
      this.overViewCharLine.destroy();
    }
    const canvasCostPlan = document.getElementById('canvas-cost-plan') as HTMLCanvasElement;
    if (canvasCostPlan) {
      const ctx: any = canvasCostPlan.getContext('2d');
      this.overViewCharLine = new Chart(ctx, {
        type: 'line',
        data: {
          labels: ['May', 'June', 'July', 'August', 'September', 'October'],
          datasets: [
            {
              type: 'line',
              label: 'Thực tế',
              data: [65, 70, 68, 75, 72, 78,],
              borderColor: 'rgb(6,189,9)',
              backgroundColor: 'rgb(6,189,9)',
              borderWidth: 3,
              fill: false,
              tension: 0.4,
              yAxisID: 'y1',
              pointRadius: 5,
              pointHoverRadius: 7,
              pointBackgroundColor: 'rgb(6,189,9)',
              pointBorderColor: 'rgb(6,189,9)',
              pointBorderWidth: 2,
            },
            {
              type: 'line',
              label: 'Thực tế',
              data: [12, 35, 68, 36, 26, 78,],
              borderColor: 'rgb(200,8,30)',
              backgroundColor: 'rgb(200,8,30)',
              borderWidth: 3,
              fill: false,
              tension: 0.4,
              yAxisID: 'y1',
              pointRadius: 5,
              pointHoverRadius: 7,
              pointBackgroundColor: 'rgb(200,8,30)',
              pointBorderColor: 'rgb(200,8,30)',
              pointBorderWidth: 2,
            },
          ],
        },
        options: ChartOptionsUtils.lineCharOptions
      })
    }
  }

  initFilterForm() {
    this.filterForm = this.fb.group({
      projectTeam: [null],
      frequency: [null],
      project: [null],
      Company: [null],
      startDate: [null],
      endDate: [null]
    });
  }

  onFilterApply() {
    if (this.filterForm.valid) {
      const formValue = this.filterForm.value;
    }
  }

  onResetFilter() {
    this.filterForm.reset()
  }


}
