import { NgModule } from '@angular/core';
import { RouterModule, Routes } from '@angular/router';
import { AuthoritiesResolverService } from '@c10t/nice-component-library';
import {
  DashboardPaybackOverTimeComponent
} from './dashboard-payback-over-time/dashboard-payback-over-time.component';
import {
  DashboardPaybackSnapshotComponent
} from './dashboard-payback-snapshot/dashboard-payback-snapshot.component';
import {
  DashboardProductivityPersonComponent
} from './dashboard-productivity-person/dashboard-productivity-person.component';
import {
  DashboardProductionOutputComponent
} from './dashboard-production-output/dashboard-production-output.component';
import {
  DashboardRevenueInventoryComponent
} from './dashboard-revenue-inventory/dashboard-revenue-inventory.component';
import {
  DashboardCostPlanComponent
} from './dashboard-cost-plan/dashboard-cost-plan.component';
import {
  DashboardCashFlowPlan
} from './dashboard-dashboard-cash-flow-plan/dashboard-cash-flow-plan';

const routes: Routes = [
  {
    path: 'payback-project-over-time',
    component: DashboardPaybackOverTimeComponent,
    data: { breadcrumb: 'menu.dashboard.payback-timeline' },
    resolve: { me: AuthoritiesResolverService }
  },
  {
    path: 'payback-project-snapshot',
    component: DashboardPaybackSnapshotComponent,
    data: { breadcrumb: 'menu.dashboard.payback-project-snapshot' },
    resolve: { me: AuthoritiesResolverService }
  },
  {
    path: 'productivity-person',
    component: DashboardProductivityPersonComponent,
    data: { breadcrumb: 'menu.dashboard.productivity-person' },
    resolve: { me: AuthoritiesResolverService }
  },
  {
    path: 'production-output',
    component: DashboardProductionOutputComponent,
    data: { breadcrumb: 'menu.dashboard.production-output' },
    resolve: { me: AuthoritiesResolverService }
  },
  {
    path: 'revenue-inventory',
    component: DashboardRevenueInventoryComponent,
    data: { breadcrumb: 'menu.dashboard.revenue-inventory' },
    resolve: { me: AuthoritiesResolverService }
  },
  {
    path: 'cost-plan',
    component: DashboardCostPlanComponent,
    data: { breadcrumb: 'menu.dashboard.cost-plan' },
    resolve: { me: AuthoritiesResolverService }
  },
  {
    path: 'cash-flow-plan',
    component: DashboardCashFlowPlan,
    data: { breadcrumb: 'menu.dashboard.cash-flow-plan' },
    resolve: { me: AuthoritiesResolverService }
  }
];

@NgModule({
  imports: [RouterModule.forChild(routes)],
  exports: [RouterModule]
})
export class DashboardChildRoutingModule {}

